from collections import deque


class _N:
    __slots__ = ("val", "left", "right")
    def __init__(self, v): self.val = v; self.left = None; self.right = None


def _build(vals):
    if not vals or vals[0] is None: return None
    root = _N(vals[0]); q = deque([root]); i = 1
    while q and i < len(vals):
        n = q.popleft()
        if i < len(vals):
            if vals[i] is not None: n.left = _N(vals[i]); q.append(n.left)
            i += 1
        if i < len(vals):
            if vals[i] is not None: n.right = _N(vals[i]); q.append(n.right)
            i += 1
    return root


def is_subtree(root, sub_root):
    r = _build(root)
    s = _build(sub_root)

    def same(a, b):
        if a is None and b is None:
            return True
        if a is None or b is None:
            return False
        return a.val == b.val and same(a.left, b.left) and same(a.right, b.right)

    def contains(node):
        if node is None:
            return s is None
        if same(node, s):
            return True
        return contains(node.left) or contains(node.right)

    return contains(r)
